// 1. Ürüne Git (AC1)
_ProductDetailPage.default.goToFirstProduct();
_ProductDetailPage.default.productTitle.should('be.visible');
// 2. Detay Kontrolü (AC2 & AC3)
_ProductDetailPage.default.verifyProductDetails();
// 3. Sepete Ekle (AC4)
cy.intercept('POST', '**/srv/service/cart/add-to-cart').as('addToCart');
_ProductDetailPage.default.addToCartBtn.should('be.visible').click({
  force: true
});
// 4. API ve Sepet Kontrolü (AC5 & AC6)
cy.wait('@addToCart', {
  timeout: 20000
}).then(interception => {
  expect(interception.response.statusCode).to.eq(200);
  cy.wait(2000);
  cy.reload();
  cy.cleanUI();
  // SAYAÇ KONTROLÜ
  _ProductDetailPage.default.basketIcon.should('exist').then($el => {
    const basketText = $el.text();
    const countMatch = basketText.match(/\d+/);
    const count = countMatch ? parseInt(countMatch[0]) : 0;
    expect(count, 'Sepet hala boş!').to.be.at.least(1);
  });
  // Onay Metni
  cy.contains(/sepet|eklendi/i).should('exist');
});
